const items = $input.all();
const feedbackItems = items
  .map(function(item) {
    return {
      text: (item.json.text || item.json.Text || '').toString().trim(),
      source: (item.json.source || item.json.Source || 'Unknown').toString().trim(),
      date: (item.json.date || item.json.Date || '').toString().trim()
    };
  })
  .filter(function(item) { return item.text !== ''; });

const sources = feedbackItems.map(function(i) { return i.source; });
const uniqueSources = sources.filter(function(v, i) { return sources.indexOf(v) === i; });

const system = 'You are a product manager synthesizing user research. Group customer feedback into named themes.';
const user = 'Cluster these feedback items into 5-10 themes. Return a JSON array ONLY with no markdown and no explanation. Each element: theme_id (integer), theme_name (3-6 word noun phrase), items (array with text and source fields). Start with [ and end with ].\n\nFeedback:\n' + JSON.stringify(feedbackItems);

return [{
  json: {
    total_items: feedbackItems.length,
    source_count: uniqueSources.length,
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 4096,
      system: system,
      messages: [{ role: 'user', content: user }]
    })
  }
}];

const item = $input.first();
let text = item.json.content[0].text.trim();

// Strip markdown code fences if Claude wrapped the JSON
if (text.charAt(0) !== '[') {
  const start = text.indexOf('[');
  const end = text.lastIndexOf(']');
  if (start !== -1 && end !== -1) {
    text = text.slice(start, end + 1);
  }
}
const clusters = JSON.parse(text);

const system = 'You are a product manager prioritizing a backlog using a RICE-adjacent scoring framework.';
const user = 'Score each of these feedback theme clusters on 4 dimensions (1-10 each):\n- frequency: relative cluster size vs others (10 = most mentions)\n- sentiment: emotional charge and urgency (10 = highest)\n- revenue_signal: connection to churn, enterprise accounts, or upgrade blockers (10 = strongest)\n- effort_hint: apparent implementation complexity (10 = simplest to build)\n\nComposite score: Math.round((frequency*2 + sentiment*2 + revenue_signal*3 + effort_hint*1) / 8 * 10)\n\nReturn JSON array ONLY — no markdown, no explanation. Each element: theme_id, theme_name, item_count, frequency_score, sentiment_score, revenue_signal_score, effort_hint_score, composite_score, scoring_rationale (2 sentences). Start with [ end with ].\n\nClusters:\n' + JSON.stringify(clusters);

return [{
  json: {
    total_items: $node['Code - Normalize'].json.total_items,
    source_count: $node['Code - Normalize'].json.source_count,
    clusters: clusters,
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 2048,
      system: system,
      messages: [{ role: 'user', content: user }]
    })
  }
}];

const item = $input.first();
let text = item.json.content[0].text.trim();

// Strip markdown code fences if Claude wrapped the JSON
if (text.charAt(0) !== '[') {
  const start = text.indexOf('[');
  const end = text.lastIndexOf(']');
  if (start !== -1 && end !== -1) {
    text = text.slice(start, end + 1);
  }
}
const scores = JSON.parse(text);
scores.sort(function(a, b) { return b.composite_score - a.composite_score; });

const clusters = $node['Code - Parse Clusters'].json.clusters;
const today = new Date().toISOString().split('T')[0];
const totalItems = $node['Code - Normalize'].json.total_items;
const sourceCount = $node['Code - Normalize'].json.source_count;

const header = '# Feature Request Intelligence Report\n**Generated:** ' + today + '\n**Sources:** ' + totalItems + ' items across ' + sourceCount + ' sources\n**Themes identified:** ' + scores.length;

const system = 'You are a senior product manager writing an intelligence report. Be direct, specific, and strategic. Write for time-constrained PMs and stakeholders.';
const user = 'Write a Markdown feature request intelligence report. Start with this exact header block (copy verbatim):\n\n' + header + '\n\nThen include:\n1. ## Executive Summary (2-3 sentences on what customers want most and why it matters now)\n2. ## Prioritized Themes — one ### subsection per theme with: score, frequency, sentiment, revenue signal, 2 representative quotes from the cluster items, 1-sentence recommendation\n3. ## Recommended Next Actions (3 concrete bullets)\n\nScored themes (sorted by priority):\n' + JSON.stringify(scores) + '\n\nOriginal clusters with full quote list:\n' + JSON.stringify(clusters);

return [{
  json: {
    filename: 'REPLACE_WITH_YOUR_OUTPUT_PATH/' + today + '-feature-request-report.md',
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: 4096,
      system: system,
      messages: [{ role: 'user', content: user }]
    })
  }
}];

const item = $input.first();
const reportContent = item.json.content[0].text;
const filename = $node['Code - Parse Scores'].json.filename;

return [{
  json: {
    filename: filename,
    report: reportContent,
    body: JSON.stringify({
      filename: filename,
      content: reportContent
    })
  }
}];
